"use client";

import { createHalaqahAction, createStudentAction, createTeacherAction, toggleStudentAction } from "@/app/actions";
import { Avatar, EmptyState, StatusBadge } from "@/components/shared";
import type { getMasterData } from "@/lib/data";
import { Building2, GraduationCap, Plus, UsersRound } from "lucide-react";
import { useState } from "react";

type MasterData = Awaited<ReturnType<typeof getMasterData>>;
type TabKey = "santri" | "ustadz" | "halaqah" | "referensi";

const tabs: Array<{ key: TabKey; label: string; icon: typeof UsersRound }> = [
  { key: "santri", label: "Santri", icon: UsersRound },
  { key: "ustadz", label: "Ustadz", icon: GraduationCap },
  { key: "halaqah", label: "Halaqah", icon: Building2 },
  { key: "referensi", label: "Referensi", icon: Plus },
];

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return <label className="block"><span className="mb-1.5 block text-xs font-bold text-slate-600">{label}</span>{children}</label>;
}
const inputClass = "w-full rounded-xl border border-slate-200 bg-white px-3 py-2.5 text-sm text-slate-800 outline-none transition placeholder:text-slate-300 focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10";

export function MasterDataManager({ data }: { data: MasterData }) {
  const [tab, setTab] = useState<TabKey>("santri");
  return <div><div className="mb-5 flex gap-1 overflow-x-auto rounded-xl border border-slate-200 bg-white p-1">{tabs.map((item) => { const Icon = item.icon; return <button type="button" key={item.key} onClick={() => setTab(item.key)} className={`flex shrink-0 items-center gap-2 rounded-lg px-3.5 py-2 text-sm font-bold transition ${tab === item.key ? "bg-emerald-900 text-white shadow-sm" : "text-slate-500 hover:bg-slate-50"}`}><Icon size={16}/>{item.label}</button>; })}</div>{tab === "santri" && <Students data={data}/>} {tab === "ustadz" && <Teachers data={data}/>} {tab === "halaqah" && <Halaqahs data={data}/>} {tab === "referensi" && <References data={data}/>}</div>;
}

function Students({ data }: { data: MasterData }) {
  return <div className="grid gap-5 xl:grid-cols-[minmax(0,1fr)_350px]"><section className="overflow-hidden rounded-2xl border border-slate-200 bg-white shadow-sm"><div className="flex items-center justify-between border-b border-slate-100 px-5 py-4"><div><h2 className="font-display text-lg font-bold">Data Santri</h2><p className="mt-1 text-xs text-slate-500">{data.students.length} data terdaftar</p></div><span className="rounded-full bg-emerald-50 px-3 py-1 text-xs font-bold text-emerald-700">Mode tanpa akun santri</span></div><div className="divide-y divide-slate-100">{data.students.map((student) => <div key={student.id} className="flex items-center gap-3 px-5 py-4"><Avatar name={student.name}/><div className="min-w-0 flex-1"><div className="flex flex-wrap items-center gap-2"><p className="truncate text-sm font-bold text-slate-800">{student.name}</p>{!student.isActive && <span className="rounded bg-slate-100 px-1.5 py-0.5 text-[10px] font-bold text-slate-500">Nonaktif</span>}</div><p className="mt-0.5 truncate text-xs text-slate-500">{student.nis} · {student.className ?? "Belum ada kelas"} · {student.halaqahName ?? "Belum ada halaqah"}</p></div><form action={toggleStudentAction}><input type="hidden" name="id" value={student.id}/><input type="hidden" name="active" value={String(student.isActive)}/><button className="rounded-lg border border-slate-200 px-2.5 py-1.5 text-[11px] font-bold text-slate-600 transition hover:border-emerald-300 hover:text-emerald-700">{student.isActive ? "Nonaktifkan" : "Aktifkan"}</button></form></div>)}{!data.students.length && <EmptyState title="Belum ada data santri" description="Tambahkan santri pertama melalui formulir di samping."/>}</div></section><form action={createStudentAction} className="h-fit rounded-2xl border border-emerald-100 bg-emerald-50/50 p-5 shadow-sm"><div className="mb-5 flex items-center gap-2"><span className="grid size-9 place-items-center rounded-xl bg-emerald-900 text-white"><Plus size={18}/></span><div><h2 className="font-display font-bold text-slate-900">Tambah Santri</h2><p className="text-xs text-slate-500">Data pokok dan penempatan</p></div></div><div className="space-y-3"><Field label="NIS"><input className={inputClass} name="nis" placeholder="Contoh: ST-25006" required/></Field><Field label="Nama lengkap"><input className={inputClass} name="name" placeholder="Nama santri" required/></Field><Field label="Jenis kelamin"><select className={inputClass} name="gender" defaultValue="putra"><option value="putra">Putra</option><option value="putri">Putri</option></select></Field><Field label="Kelas"><select className={inputClass} name="classId" defaultValue=""><option value="">Pilih kelas</option>{data.classes.map((item) => <option value={item.id} key={item.id}>{item.name}</option>)}</select></Field><Field label="Asrama / kamar"><select className={inputClass} name="dormId" defaultValue=""><option value="">Pilih asrama</option>{data.dorms.map((item) => <option value={item.id} key={item.id}>{item.name}</option>)}</select></Field><Field label="Halaqah"><select className={inputClass} name="halaqahId" defaultValue=""><option value="">Pilih halaqah</option>{data.halaqahs.map((item) => <option value={item.id} key={item.id}>{item.name}</option>)}</select></Field><Field label="Wali santri"><select className={inputClass} name="parentId" defaultValue=""><option value="">Pilih wali</option>{data.parents.map((item) => <option value={item.id} key={item.id}>{item.name} · {item.relation}</option>)}</select></Field><Field label="Tahun masuk"><input className={inputClass} name="enrollmentYear" placeholder="2025"/></Field><button className="mt-2 w-full rounded-xl bg-emerald-900 px-4 py-3 text-sm font-bold text-white transition hover:bg-emerald-800">Simpan Data Santri</button></div></form></div>;
}

function Teachers({ data }: { data: MasterData }) {
  return <div className="grid gap-5 xl:grid-cols-[minmax(0,1fr)_350px]"><section className="overflow-hidden rounded-2xl border border-slate-200 bg-white shadow-sm"><div className="border-b border-slate-100 px-5 py-4"><h2 className="font-display text-lg font-bold">Data Ustadz / Musyrif</h2><p className="mt-1 text-xs text-slate-500">Pengampu halaqah dan penilai setoran</p></div><div className="divide-y divide-slate-100">{data.teachers.map((teacher) => <div key={teacher.id} className="flex items-center gap-3 px-5 py-4"><Avatar name={teacher.name} className="bg-sky-600"/><div className="min-w-0 flex-1"><p className="text-sm font-bold text-slate-800">{teacher.name}</p><p className="mt-0.5 text-xs text-slate-500">{teacher.nip} · {teacher.specialization ?? "Pengampu"}</p></div><span className="rounded-full bg-emerald-50 px-2.5 py-1 text-[10px] font-bold text-emerald-700">Aktif</span></div>)}</div></section><form action={createTeacherAction} className="h-fit rounded-2xl border border-sky-100 bg-sky-50/60 p-5 shadow-sm"><div className="mb-5 flex items-center gap-2"><span className="grid size-9 place-items-center rounded-xl bg-sky-600 text-white"><Plus size={18}/></span><div><h2 className="font-display font-bold text-slate-900">Tambah Ustadz</h2><p className="text-xs text-slate-500">Profil pengampu halaqah</p></div></div><div className="space-y-3"><Field label="NIP"><input className={inputClass} name="nip" placeholder="Contoh: UST-003" required/></Field><Field label="Nama lengkap"><input className={inputClass} name="name" placeholder="Nama ustadz" required/></Field><Field label="Jenis kelamin"><select className={inputClass} name="gender" defaultValue="putra"><option value="putra">Putra</option><option value="putri">Putri</option></select></Field><Field label="Keahlian"><input className={inputClass} name="specialization" placeholder="Contoh: Tahfidz Al-Qur'an"/></Field><Field label="Nomor telepon"><input className={inputClass} name="phone" placeholder="08xxxxxxxxxx"/></Field><button className="mt-2 w-full rounded-xl bg-sky-600 px-4 py-3 text-sm font-bold text-white transition hover:bg-sky-700">Simpan Data Ustadz</button></div></form></div>;
}

function Halaqahs({ data }: { data: MasterData }) {
  return <div className="grid gap-5 xl:grid-cols-[minmax(0,1fr)_350px]"><section className="grid gap-4 md:grid-cols-2">{data.halaqahs.map((halaqah) => <article key={halaqah.id} className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm"><div className="flex items-start justify-between"><span className="grid size-11 place-items-center rounded-xl bg-amber-50 text-amber-700"><Building2 size={21}/></span><span className="rounded-full bg-slate-100 px-2.5 py-1 text-[10px] font-bold text-slate-600">{halaqah.gender === "putra" ? "Putra" : "Putri"}</span></div><h2 className="mt-4 font-display text-lg font-bold text-slate-900">{halaqah.name}</h2><p className="mt-1 text-sm text-slate-500">{halaqah.teacherName ?? "Belum ada pengampu"}</p><dl className="mt-4 grid grid-cols-2 gap-2 border-t border-slate-100 pt-4 text-xs"><div><dt className="text-slate-400">Tempat</dt><dd className="mt-1 font-semibold text-slate-700">{halaqah.meetingPlace ?? "—"}</dd></div><div><dt className="text-slate-400">Jadwal</dt><dd className="mt-1 font-semibold text-slate-700">{halaqah.schedule ?? "—"}</dd></div></dl></article>)}{!data.halaqahs.length && <EmptyState title="Belum ada halaqah" description="Buat kelompok bimbingan pertama."/>}</section><form action={createHalaqahAction} className="h-fit rounded-2xl border border-amber-100 bg-amber-50/60 p-5 shadow-sm"><div className="mb-5 flex items-center gap-2"><span className="grid size-9 place-items-center rounded-xl bg-amber-500 text-white"><Plus size={18}/></span><div><h2 className="font-display font-bold text-slate-900">Buat Halaqah</h2><p className="text-xs text-slate-500">Atur pengampu dan tempat setoran</p></div></div><div className="space-y-3"><Field label="Nama halaqah"><input className={inputClass} name="name" placeholder="Contoh: Halaqah Al-Falah" required/></Field><Field label="Kelompok"><select className={inputClass} name="gender" defaultValue="putra"><option value="putra">Putra</option><option value="putri">Putri</option></select></Field><Field label="Ustadz pengampu"><select className={inputClass} name="teacherId" defaultValue=""><option value="">Pilih ustadz</option>{data.teachers.map((item) => <option value={item.id} key={item.id}>{item.name}</option>)}</select></Field><Field label="Tempat setoran"><input className={inputClass} name="meetingPlace" placeholder="Contoh: Masjid Utama"/></Field><Field label="Jadwal"><input className={inputClass} name="schedule" placeholder="Contoh: Ba'da Subuh"/></Field><button className="mt-2 w-full rounded-xl bg-amber-500 px-4 py-3 text-sm font-bold text-white transition hover:bg-amber-600">Simpan Halaqah</button></div></form></div>;
}

function References({ data }: { data: MasterData }) {
  const blocks = [
    { title: "Tahun Ajaran", rows: data.academicYears.map((item) => item.name), hint: "Periode pembelajaran aktif" },
    { title: "Kelas", rows: data.classes.map((item) => item.name), hint: "Pembagian kelas santri" },
    { title: "Asrama", rows: data.dorms.map((item) => `${item.name}${item.building ? ` · ${item.building}` : ""}`), hint: "Penempatan kamar/asrama" },
    { title: "Wali Santri", rows: data.parents.map((item) => `${item.name} · ${item.relation}`), hint: "Akses portal wali" },
  ];
  return <div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{blocks.map((block) => <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm" key={block.title}><h2 className="font-display font-bold text-slate-900">{block.title}</h2><p className="mt-1 text-xs text-slate-500">{block.hint}</p><ul className="mt-4 space-y-2">{block.rows.map((row) => <li className="rounded-lg bg-slate-50 px-3 py-2 text-xs font-medium text-slate-600" key={row}>{row}</li>)}</ul></section>)}</div>;
}
